"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["5009"],{537(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/neuralPilot/docs/intro","label":"Introduction to NeuroPilot","docId":"intro","unlisted":false},{"type":"link","href":"/neuralPilot/docs/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"category","label":"API & CLI Reference","items":[{"type":"link","href":"/neuralPilot/docs/api/cli-reference","label":"CLI Reference Manual","docId":"api/cli-reference","unlisted":false},{"type":"link","href":"/neuralPilot/docs/api/python-sdk","label":"Python SDK Reference Manual","docId":"api/python-sdk","unlisted":false}],"collapsed":false,"collapsible":true},{"type":"category","label":"Neural Architecture","items":[{"type":"link","href":"/neuralPilot/docs/architecture/backbones","label":"Modular Backbones & Feature Extractor","docId":"architecture/backbones","unlisted":false},{"type":"link","href":"/neuralPilot/docs/architecture/neck-routing","label":"Neck & Feature Routing Topologies","docId":"architecture/neck-routing","unlisted":false},{"type":"link","href":"/neuralPilot/docs/architecture/task-heads","label":"Task Heads","docId":"architecture/task-heads","unlisted":false},{"type":"link","href":"/neuralPilot/docs/architecture/loss-functions","label":"Loss Functions & Regularizers","docId":"architecture/loss-functions","unlisted":false}],"collapsed":false,"collapsible":true},{"type":"category","label":"Data Engineering","items":[{"type":"link","href":"/neuralPilot/docs/data/custom-datasets","label":"Custom Dataset Integration","docId":"data/custom-datasets","unlisted":false},{"type":"link","href":"/neuralPilot/docs/data/video-pipelines","label":"Temporal Video Pipelines","docId":"data/video-pipelines","unlisted":false}],"collapsed":false,"collapsible":true},{"type":"category","label":"Edge Deployment","items":[{"type":"link","href":"/neuralPilot/docs/deploy/export-onnx-trt","label":"Model Export (ONNX & TensorRT)","docId":"deploy/export-onnx-trt","unlisted":false},{"type":"link","href":"/neuralPilot/docs/deploy/jetson-inference","label":"Jetson Inference & Runtime","docId":"deploy/jetson-inference","unlisted":false}],"collapsed":false,"collapsible":true},{"type":"category","label":"Advanced Customization","items":[{"type":"link","href":"/neuralPilot/docs/advanced/customization","label":"Advanced Customization & Extension","docId":"advanced/customization","unlisted":false}],"collapsed":false,"collapsible":true}]},"docs":{"advanced/customization":{"id":"advanced/customization","title":"Advanced Customization & Extension","description":"NeuroPilot is designed following the Open-Closed Principle (OCP). You do not need to modify the core codebase to experiment with custom layers, custom routing necks, new task loss formulations, or specialized training loops. Instead, you can extend the framework by writing modular custom code and linking it via config files and decorators.","sidebar":"tutorialSidebar"},"api/cli-reference":{"id":"api/cli-reference","title":"CLI Reference Manual","description":"NeuroPilot provides a unified Command Line Interface (CLI) entrypoint via the neuropilot executable. This document serves as the exhaustive command reference, documenting every subcommand, option flags, defaults, constraints, hyperparameter overrides, and realistic execution stdout.","sidebar":"tutorialSidebar"},"api/python-sdk":{"id":"api/python-sdk","title":"Python SDK Reference Manual","description":"This document serves as the comprehensive Python API and SDK guide for NeuroPilot. We document class signatures, runtime arguments, data schemas, output prediction classes, and custom callbacks with fully compilable code blocks.","sidebar":"tutorialSidebar"},"architecture/backbones":{"id":"architecture/backbones","title":"Modular Backbones & Feature Extractor","description":"The backbone acts as the primary visual feature encoder of NeuroPilot. It transforms raw image tensors of shape [3 x H x W] into hierarchical multi-scale feature maps. This document details the visual stage hierarchies, channel scaling rules, Timm integrations, and comparison tables.","sidebar":"tutorialSidebar"},"architecture/loss-functions":{"id":"architecture/loss-functions","title":"Loss Functions & Regularizers","description":"NeuroPilot optimizes multiple tasks using a joint loss function. This guide documents the mathematical foundations of the specialized loss functions and regularizers.","sidebar":"tutorialSidebar"},"architecture/neck-routing":{"id":"architecture/neck-routing","title":"Neck & Feature Routing Topologies","description":"The Neck layer coordinates the aggregation and routing of features before they reach task-specific heads. Multi-task learning environments often suffer from \\"gradient conflict\\"\u2014where gradients from the detection task degrade the representation quality needed for path planning. NeuroPilot resolves this using three specialized routing topologies.","sidebar":"tutorialSidebar"},"architecture/task-heads":{"id":"architecture/task-heads","title":"Task Heads","description":"NeuroPilot distributes predictions into dedicated head modules, which can be selectively enabled or disabled during training using loss weight multiplier configs (lambdas).","sidebar":"tutorialSidebar"},"data/custom-datasets":{"id":"data/custom-datasets","title":"Custom Dataset Integration","description":"NeuroPilot utilizes the Open-Closed Principle (OCP) for dataset loading. By implementing a central registry, you can add support for any new dataset format (such as nuScenes, CARLA simulator logs, CoVLA, or custom sensor recording pipelines) with zero modifications to the core repository engine.","sidebar":"tutorialSidebar"},"data/video-pipelines":{"id":"data/video-pipelines","title":"Temporal Video Pipelines","description":"Autonomous driving depends on understanding motion and temporal changes. NeuroPilot provides native support for temporal training pipelines to train models directly on video feeds using the Decord video reading library.","sidebar":"tutorialSidebar"},"deploy/export-onnx-trt":{"id":"deploy/export-onnx-trt","title":"Model Export (ONNX & TensorRT)","description":"Deploying multi-task neural networks on edge robotics platforms requires converting PyTorch graphs (.pt) to optimized formats compatible with low-latency runtimes.","sidebar":"tutorialSidebar"},"deploy/jetson-inference":{"id":"deploy/jetson-inference","title":"Jetson Inference & Runtime","description":"After compiling your TensorRT engine, you can run inference using our optimized edge runtimes. This guide covers preprocessing, execution contexts, and troubleshooting edge memory issues.","sidebar":"tutorialSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"This guide provides a comprehensive setup walk-through for NeuroPilot. We cover system prerequisites, multi-environment installation (using uv, native pip virtual environments, or Docker), CLI operations, validation procedures, and basic programmatic integration.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction to NeuroPilot","description":"Welcome to the documentation for NeuroPilot \u2014 a unified, high-performance end-to-end (E2E) autonomous driving framework designed for multi-task perception and real-time edge deployment.","sidebar":"tutorialSidebar"}}}}')}}]);